// src/AddNew.jsx
import React from "react";
import { useNavigate } from "react-router-dom";
import "./AddNew.css";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function AddNew({ employee }) {
  const navigate = useNavigate();

  return (
    <div className="addnew-outer">
      <div className="addnew-card">

        {/* Header */}
        <div className="addnew-header">
          <button onClick={() => navigate("/home")} className="addnew-back">
            ⬅ Back
          </button>
          <h2 style={{ color: green }}>Add New</h2>
        </div>

        <p className="addnew-emp">
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* Cards */}
        <div className="addnew-cards">

          {/* Travel */}
          <div className="addnew-card-box" onClick={() => navigate("/add-travel")}>
            <h3>Add Travel Expense</h3>
            <p>Add new travel entry with purpose & amount.</p>
          </div>

          {/* Ticket */}
          <div className="addnew-card-box" onClick={() => navigate("/add-ticket")}>
            <h3>Add Ticket Expense</h3>
            <p>Add new ticket entry with purpose & amount.</p>
          </div>

          {/* ✅ NEW — ADD BILLS */}
          <div className="addnew-card-box" onClick={() => navigate("/tools/upload-bills")}>
            <h3>Upload Bills</h3>
            <p>Upload bills & receipts for reimbursement.</p>
          </div>

        </div>
      </div>
    </div>
  );
}
